class Solution:
    def getSkyline(self, buildings):
        # Collect all x-coordinates
        xs = set()
        for l, r, h in buildings:
            xs.add(l)
            xs.add(r)
        result = []
        prev_h = 0
        for x in sorted(xs):
            # current max height at x
            cur_h = 0
            for l, r, h in buildings:
                if l <= x < r:
                    cur_h = max(cur_h, h)
            if cur_h != prev_h:
                result.append([x, cur_h])
                prev_h = cur_h
        return result

