class Solution:
    def getSkyline(self, buildings):
        import heapq
        events = []
        for l, r, h in buildings:
            events.append((l, -h, r))
            events.append((r, 0, 0))
        events.sort()
        result = []
        # max-heap: store (-height, end_x)
        heap = [(0, float('inf'))]
        prev_max = 0
        for x, neg_h, end in events:
            if neg_h != 0:
                heapq.heappush(heap, (neg_h, end))
            # remove expired buildings
            while heap[0][1] <= x:
                heapq.heappop(heap)
            cur_max = -heap[0][0]
            if cur_max != prev_max:
                result.append([x, cur_max])
                prev_max = cur_max
        return result

